import React, { forwardRef, type PropsWithChildren } from "react";
import { ResponsiveElement, useSeparator } from "../../factory";
import type {IGridComponent, IStyleClasses} from "@lmb-it/kitsconcerto-types";

type IsolatedGrid = Omit<IGridComponent, keyof IStyleClasses>

const Grid = forwardRef<any, PropsWithChildren<IGridComponent>>((props, ref) => {
    const { cssProps, nativeProps } = useSeparator<IsolatedGrid>(props);
    const { children, ...rest } = nativeProps;

    return (
        <ResponsiveElement<IsolatedGrid>
            ref={ref}
            nativeProps={rest}
            cssProps={cssProps}
            additionalStyles={{
                //@ts-ignore
                display: "grid"
            }}
        >
            {children}
        </ResponsiveElement>
    );
});

export default Grid;
